--
-- Name: update_case_completion_percentage(); Type: FUNCTION; Schema: public; Owner: acs_user
--

CREATE FUNCTION public.update_case_completion_percentage() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE cases 
    SET 
        completed_tasks_count = (
            SELECT COUNT(*) 
            FROM verification_tasks 
            WHERE case_id = NEW.case_id AND status = 'COMPLETED'
        ),
        case_completion_percentage = (
            SELECT 
                CASE 
                    WHEN COUNT(*) = 0 THEN 0
                    ELSE ROUND(
                        COUNT(CASE WHEN status = 'COMPLETED' THEN 1 END)::DECIMAL / 
                        COUNT(*)::DECIMAL * 100, 2
                    )
                END
            FROM verification_tasks 
            WHERE case_id = NEW.case_id
        ),
        "updatedAt" = CURRENT_TIMESTAMP
    WHERE id = NEW.case_id;
    
    RETURN NEW;
END;
$$;


ALTER FUNCTION public.update_case_completion_percentage() OWNER TO acs_user;

