    CONSTRAINT chk_verification_tasks_applicant_type CHECK (((applicant_type IS NULL) OR ((applicant_type)::text = ANY ((ARRAY['APPLICANT'::character varying, 'CO-APPLICANT'::character varying, 'REFERENCE PERSON'::character varying])::text[]))))
