    updated_at timestamp without time zone DEFAULT now(),
    CONSTRAINT form_submissions_attachments_count_check CHECK ((attachments_count >= 0)),
    CONSTRAINT form_submissions_form_type_check CHECK (((form_type)::text = ANY ((ARRAY['RESIDENCE'::character varying, 'OFFICE'::character varying, 'BUSINESS'::character varying, 'BUILDER'::character varying, 'RESIDENCE_CUM_OFFICE'::character varying, 'DSA_CONNECTOR'::character varying, 'PROPERTY_APF'::character varying, 'PROPERTY_INDIVIDUAL'::character varying, 'NOC'::character varying])::text[]))),
    CONSTRAINT form_submissions_photos_count_check CHECK ((photos_count >= 0)),
    CONSTRAINT form_submissions_submission_score_check CHECK (((submission_score >= (0)::numeric) AND (submission_score <= (100)::numeric))),
    CONSTRAINT form_submissions_time_spent_minutes_check CHECK ((time_spent_minutes >= 0)),
    CONSTRAINT form_submissions_validation_status_check CHECK (((validation_status)::text = ANY ((ARRAY['PENDING'::character varying, 'VALID'::character varying, 'INVALID'::character varying, 'REQUIRES_REVIEW'::character varying])::text[])))
